    /**
     * @method
     * @name bitbank#fetchOHLCV
     * @description fetches historical candlestick data containing the open, high, low, and close price, and the volume of a market
     * @see https://github.com/bitbankinc/bitbank-api-docs/blob/38d6d7c6f486c793872fd4b4087a0d090a04cd0a/public-api.md#candlestick
     * @param {string} symbol unified symbol of the market to fetch OHLCV data for
     * @param {string} timeframe the length of time each candle represents
     * @param {int} [since] timestamp in ms of the earliest candle to fetch
     * @param {int} [limit] the maximum amount of candles to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {int[][]} A list of candles ordered as timestamp, open, high, low, close, volume
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOHLCV(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object timeframe = Helpers.getArg(optionalArgs, 0, "1m");
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(since, null)))
            {
                if (Helpers.isTrue(Helpers.isEqual(limit, null)))
                {
                    limit = 1000; // it doesn't have any defaults, might return 200, might 2000 (i.e. https://public.bitbank.cc/btc_jpy/candlestick/4hour/2020)
                }
                Object duration = this.parseTimeframe(timeframe);
                since = Helpers.subtract(this.milliseconds(), Helpers.multiply(Helpers.multiply(duration, 1000), limit));
            }
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = this.market(symbol);
            final Object finalSince = since;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "pair", Helpers.GetValue(market, "id") );
                put( "candletype", BitbankCore.this.safeString(BitbankCore.this.timeframes, timeframe, timeframe) );
                put( "yyyymmdd", BitbankCore.this.yyyymmdd(finalSince, "") );
            }};
            Object response = (this.publicGetPairCandlestickCandletypeYyyymmdd(this.extend(request, parameters))).join();
            //
            //     {
            //         "success":1,
            //         "data":{
            //             "candlestick":[
            //                 {
            //                     "type":"5min",
            //                     "ohlcv":[
            //                         ["0.02501786","0.02501786","0.02501786","0.02501786","0.0000",1591488000000],
            //                         ["0.02501747","0.02501953","0.02501747","0.02501953","0.3017",1591488300000],
            //                         ["0.02501762","0.02501762","0.02500392","0.02500392","0.1500",1591488600000],
            //                     ]
            //                 }
            //             ],
            //             "timestamp":1591508668190
            //         }
            //     }
            //
            Object data = this.safeValue(response, "data", new java.util.HashMap<String, Object>() {{}});
            Object candlestick = this.safeValue(data, "candlestick", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object first = this.safeValue(candlestick, 0, new java.util.HashMap<String, Object>() {{}});
            Object ohlcv = this.safeList(first, "ohlcv", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseOHLCVs(ohlcv, market, timeframe, since, limit);
        });

    }

    public Object parseBalance(Object response)
    {
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", response );
            put( "timestamp", null );
            put( "datetime", null );
        }};
        Object data = this.safeValue(response, "data", new java.util.HashMap<String, Object>() {{}});
        Object assets = this.safeValue(data, "assets", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(assets)); i++)
        {
            Object balance = Helpers.GetValue(assets, i);
            Object currencyId = this.safeString(balance, "asset");
            Object code = this.safeCurrencyCode(currencyId);
            Object account = this.account();
            Helpers.addElementToObject(account, "free", this.safeString(balance, "free_amount"));
            Helpers.addElementToObject(account, "used", this.safeString(balance, "locked_amount"));
            Helpers.addElementToObject(account, "total", this.safeString(balance, "onhand_amount"));
            Helpers.addElementToObject(result, code, account);
        }
        return this.safeBalance(result);
    }

