    /**
     * @method
     * @name bitbank#withdraw
     * @description make a withdrawal
     * @see https://github.com/bitbankinc/bitbank-api-docs/blob/38d6d7c6f486c793872fd4b4087a0d090a04cd0a/rest-api.md#new-withdrawal-request
     * @param {string} code unified currency code
     * @param {float} amount the amount to withdraw
     * @param {string} address the address to withdraw to
     * @param {string} tag
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [transaction structure]{@link https://docs.ccxt.com/?id=transaction-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> withdraw(Object code, Object amount, Object address, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object tag = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            var tagparametersVariable = this.handleWithdrawTagAndParams(tag, parameters);
            tag = ((java.util.List<Object>) tagparametersVariable).get(0);
            parameters = ((java.util.List<Object>) tagparametersVariable).get(1);
            if (!Helpers.isTrue((Helpers.inOp(parameters, "uuid"))))
            {
                throw new ExchangeError((String)Helpers.add(this.id, " uuid is required for withdrawal")) ;
            }
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object currency = this.currency(code);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "asset", Helpers.GetValue(currency, "id") );
                put( "amount", amount );
            }};
            Object response = (this.privatePostUserRequestWithdrawal(this.extend(request, parameters))).join();
            //
            //     {
            //         "success": 1,
            //         "data": {
            //             "uuid": "string",
            //             "asset": "btc",
            //             "amount": 0,
            //             "account_uuid": "string",
            //             "fee": 0,
            //             "status": "DONE",
            //             "label": "string",
            //             "txid": "string",
            //             "address": "string",
            //             "requested_at": 0
            //         }
            //     }
            //
            Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            return this.parseTransaction(data, currency);
        });

    }

    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        // withdraw
        //
        //     {
        //         "uuid": "string",
        //         "asset": "btc",
        //         "amount": 0,
        //         "account_uuid": "string",
        //         "fee": 0,
        //         "status": "DONE",
        //         "label": "string",
        //         "txid": "string",
        //         "address": "string",
        //         "requested_at": 0
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object txid = this.safeString(transaction, "txid");
        currency = this.safeCurrency(null, currency);
        final Object finalCurrency = currency;
        return new java.util.HashMap<String, Object>() {{
            put( "id", txid );
            put( "txid", txid );
            put( "timestamp", null );
            put( "datetime", null );
            put( "network", null );
            put( "addressFrom", null );
            put( "address", null );
            put( "addressTo", null );
            put( "amount", null );
            put( "type", null );
            put( "currency", Helpers.GetValue(finalCurrency, "code") );
            put( "status", null );
            put( "updated", null );
            put( "tagFrom", null );
            put( "tag", null );
            put( "tagTo", null );
            put( "comment", null );
            put( "internal", null );
            put( "fee", null );
            put( "info", transaction );
        }};
    }

    public Object nonce()
    {
        return this.milliseconds();
    }

    public Object sign(Object path, Object... optionalArgs)
    {
        Object api = Helpers.getArg(optionalArgs, 0, "public");
        Object method = Helpers.getArg(optionalArgs, 1, "GET");
        Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
        Object headers = Helpers.getArg(optionalArgs, 3, null);
        Object body = Helpers.getArg(optionalArgs, 4, null);
        Object query = this.omit(parameters, this.extractParams(path));
        Object url = Helpers.add(this.implodeHostname(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), api)), "/");
        if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(api, "public"))) || Helpers.isTrue((Helpers.isEqual(api, "markets")))))
        {
            url = Helpers.add(url, this.implodeParams(path, parameters));
            if (Helpers.isTrue(Helpers.getArrayLength(Helpers.objectKeys(query))))
            {
                url = Helpers.add(url, Helpers.add("?", this.urlencode(query)));
            }
        } else
        {
            this.checkRequiredCredentials();
            Object nonce = String.valueOf(this.nonce());
            Object auth = nonce;
            url = Helpers.add(url, Helpers.add(Helpers.add(this.version, "/"), this.implodeParams(path, parameters)));
            if (Helpers.isTrue(Helpers.isEqual(method, "POST")))
            {
                body = this.json(query);
                auth = Helpers.add(auth, body);
            } else
            {
                auth = Helpers.add(auth, Helpers.add(Helpers.add(Helpers.add("/", this.version), "/"), path));
                if (Helpers.isTrue(Helpers.getArrayLength(Helpers.objectKeys(query))))
                {
                    query = this.urlencode(query);
                    url = Helpers.add(url, Helpers.add("?", query));
                    auth = Helpers.add(auth, Helpers.add("?", query));
                }
            }
            final Object finalAuth = auth;
            headers = new java.util.HashMap<String, Object>() {{
                put( "Content-Type", "application/json" );
                put( "ACCESS-KEY", BitbankCore.this.apiKey );
                put( "ACCESS-NONCE", nonce );
                put( "ACCESS-SIGNATURE", BitbankCore.this.hmac(BitbankCore.this.encode(finalAuth), BitbankCore.this.encode(BitbankCore.this.secret), sha256()) );
            }};
        }
        final Object finalUrl = url;
        final Object finalMethod = method;
        final Object finalBody = body;
        final Object finalHeaders = headers;
        return new java.util.HashMap<String, Object>() {{
            put( "url", finalUrl );
            put( "method", finalMethod );
            put( "body", finalBody );
            put( "headers", finalHeaders );
        }};
    }

